  2	import { ChartTooltip, ChartTooltipProps, ChartLabel, ChartPoint, ChartCursorFlyout } from '@patternfly/react-charts';
  3	import { VCDataPoint } from 'types/VictoryChartInfo';
  4	
  5	const dy = 15;
  6	const headSize = 2 * dy;
  7	const yMargin = 8;
  8	
  9	// eslint-disable-next-line @typescript-eslint/no-explicit-any
 10	const canvasContext: any = document.createElement('canvas').getContext('2d');
 11	// TODO: safe way to get this programmatically?
 12	canvasContext.font = '14px overpass';
 13	
 14	// eslint-disable-next-line @typescript-eslint/no-explicit-any
 15	const CustomLabel = (props: any & { head?: string; text: string[]; textWidth: number }) => {
 16	  const x = props.x - 11 - props.textWidth / 2;
 17	  const textsWithHead = props.head ? [props.head, ' '].concat(props.text) : props.text;
 18	  const headSize = props.head ? 2 * dy : 0;
 19	  const startY = yMargin + props.y - (textsWithHead.length * dy) / 2 + headSize;
 20	
 21	  return (
 22	    <>
 23	      {props.activePoints &&
 24	        props.activePoints
 25	          .filter(pt => pt.color && !pt.hideLabel)
 26	          .map((pt, idx) => {
 27	            const symbol = pt.symbol || 'square';
 28	            return (
 29	              <ChartPoint
 30	                key={'item-' + idx}
 31	                style={{ fill: pt.color, type: symbol }}
 32	                x={x}
 33	                y={startY + dy * idx}
 34	                symbol={symbol}
 35	                size={5.5}
 36	              />
 37	            );
 38	          })}
 39	      <ChartLabel {...props} text={textsWithHead} />
 40	    </>
 41	  );
 42	};
 43	
 44	const getHeader = (activePoints?: VCDataPoint[]): string | undefined => {
 45	  if (activePoints && activePoints.length > 0) {
 46	    const x = activePoints[0].x;
 47	    if (typeof x === 'object') {
 48	      // Assume date
 49	      return x.toLocaleStringWithConditionalDate();
 50	    }
 51	  }
 52	  return undefined;
 53	};
 54	
 55	export type HookedTooltipProps<T> = ChartTooltipProps & {
 56	  activePoints?: (VCDataPoint & T)[];
 57	  onOpen?: (items: VCDataPoint[]) => void;
 58	  onClose?: () => void;
 59	};
 60	
 61	export class HookedChartTooltip<T> extends React.Component<HookedTooltipProps<T>> {
 62	  componentDidMount() {
 63	    if (this.props.onOpen && this.props.activePoints) {
 64	      this.props.onOpen(this.props.activePoints);
 65	    }
 66	  }
 67	
 68	  componentWillUnmount() {
 69	    if (this.props.onClose) {
 70	      this.props.onClose();
 71	    }
 72	  }
 73	
 74	  render() {
 75	    return <ChartTooltip {...this.props} />;
 76	  }
 77	}
 78	
 79	type Props = HookedTooltipProps<{}> & {
 80	  showTime?: boolean;
 81	};
 82	
 83	type State = {
 84	  texts: string[];
 85	  head?: string;
 86	  textWidth: number;
 87	  width: number;
 88	  height: number;
 89	};
 90	
 91	export class CustomTooltip extends React.Component<Props, State> {
 92	  static getDerivedStateFromProps(props: Props): State {
 93	    const head = props.showTime ? getHeader(props.activePoints) : undefined;
 94	    const texts: string[] =
 95	      props.text && Array.isArray(props.text) ? (props.text as string[]) : !props.text ? [] : [props.text as string];
 96	    let height = texts.length * dy + 2 * yMargin;
 97	    if (head) {
 98	      height += headSize;
 99	    }
100	    const textWidth = Math.max(...texts.map(t => canvasContext.measureText(t).width));
101	    const width = 50 + (head ? Math.max(textWidth, canvasContext.measureText(head).width) : textWidth);
102	    return {
103	      head: head,
104	      texts: texts,
105	      textWidth: textWidth,
106	      width: width,
107	      height: height
108	    };
109	  }
110	
111	  constructor(p: Props) {
112	    super(p);
113	    this.state = CustomTooltip.getDerivedStateFromProps(p);
114	  }
115	
116	  render() {
117	    return (
118	      <HookedChartTooltip
119	        {...this.props}
120	        text={this.state.texts}
121	        flyoutWidth={this.state.width}
122	        flyoutHeight={this.state.height}
123	        flyoutComponent={<ChartCursorFlyout style={{ stroke: 'none', fillOpacity: 0.6 }} />}
124	        labelComponent={<CustomLabel head={this.state.head} textWidth={this.state.textWidth} />}
125	      />
126	    );
127	  }
128	}

